def minimumOperationsToMakeEqual(self, x: int, y: int) -> int:
    operations = 0
    while x != y:
        if x % 11 == 0:
            x //= 11
            operations += 1
        elif x % 5 == 0:
            x //= 5
            operations += 1
        elif x > y:
            x -= 1
            operations += 1
        else:
